import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { TOOLS_DATA } from '../src/data/tools.js';
import { TOOLS_DATA_ES } from '../src/data/tools-es.js';
import { slugify } from '../src/utils/slugify.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const DIST_DIR = path.resolve(__dirname, '../dist');

// Read the base index.html generated by Vite
const indexPath = path.join(DIST_DIR, 'index.html');
if (!fs.existsSync(indexPath)) {
  console.error('Error: dist/index.html not found. Run vite build first.');
  process.exit(1);
}
const baseHtml = fs.readFileSync(indexPath, 'utf-8');

const platforms = ['mac', 'windows', 'iphone', 'android'];

function generateToolPages() {
  const routes = [];
  
  TOOLS_DATA.forEach((tool, index) => {
    const slug = slugify(tool.title);
    const esTool = TOOLS_DATA_ES[index] || tool;
    
    // English
    routes.push({
      path: `/tools/${slug}`,
      lang: 'en',
      tool,
      platform: null
    });
    
    // English Platforms
    platforms.forEach(platform => {
      routes.push({
        path: `/tools/${slug}/${platform}`,
        lang: 'en',
        tool,
        platform
      });
    });

    // Spanish
    routes.push({
      path: `/es/tools/${slug}`,
      lang: 'es',
      tool: esTool,
      platform: null
    });

    // Spanish Platforms
    platforms.forEach(platform => {
      routes.push({
        path: `/es/tools/${slug}/${platform}`,
        lang: 'es',
        tool: esTool,
        platform
      });
    });
  });

  return routes;
}

function injectContext(text, platform, isEs = false) {
  if (!text) return text;
  const platformStr = platform ? (isEs ? (platform === 'mac' ? 'tu Mac' : platform === 'windows' ? 'tu Windows' : platform === 'iphone' ? 'tu iPhone' : 'tu dispositivo Android') : `your ${platform === 'mac' ? 'Mac' : platform === 'windows' ? 'Windows' : platform === 'iphone' ? 'iPhone' : 'Android device'}`) : (isEs ? 'tu dispositivo' : 'your device');
  const capitalizedPlatformStr = platformStr.charAt(0).toUpperCase() + platformStr.slice(1);
  
  let res = text.replace(/your device/g, platformStr).replace(/Your device/g, capitalizedPlatformStr);
  if (isEs) res = res.replace(/tu dispositivo/g, platformStr).replace(/Tu dispositivo/g, capitalizedPlatformStr);
  return res;
}

const allRoutes = generateToolPages();

console.log(`Generating SEO HTML for ${allRoutes.length} tool pages...`);

allRoutes.forEach(route => {
  const { path: routePath, lang, tool, platform } = route;
  
  const displayTitle = lang === 'es' ? tool.title : tool.title; // tool is already esTool for spanish routes!
  const displayDesc = tool.desc; 
  
  const title = `${displayTitle} ${platform ? 'for ' + (platform.charAt(0).toUpperCase() + platform.slice(1)) : ''} - PDFMaster`;
  const desc = injectContext(displayDesc, platform, lang === 'es');

  const dynamicSteps = (tool.howToSteps && tool.howToSteps.length > 0) ? tool.howToSteps.map(step => injectContext(step, platform, lang === 'es')) : [];
  const dynamicFaqs = (tool.faqs && tool.faqs.length > 0) ? tool.faqs.map(faq => ({
    question: injectContext(faq.question, platform, lang === 'es'),
    answer: injectContext(faq.answer, platform, lang === 'es')
  })) : [];

  // Generate Schemas
  const schemas = [];
  
  // SoftwareApplication
  schemas.push({
    "@context": "https://schema.org",
    "@type": "WebApplication",
    "name": title,
    "applicationCategory": "UtilitiesApplication",
    "operatingSystem": platform ? (platform.charAt(0).toUpperCase() + platform.slice(1)) : "All",
    "description": desc,
    "url": `https://www.theylovepdf.com${routePath}`
  });

  // HowTo Schema
  if (dynamicSteps.length > 0) {
    schemas.push({
      "@context": "https://schema.org",
      "@type": "HowTo",
      "name": `How to use ${displayTitle} ${platform ? 'on ' + (platform.charAt(0).toUpperCase() + platform.slice(1)) : ''}`,
      "description": desc,
      "step": dynamicSteps.map((step, index) => ({
        "@type": "HowToStep",
        "position": index + 1,
        "text": step
      }))
    });
  }

  // FAQPage Schema
  if (dynamicFaqs.length > 0) {
    schemas.push({
      "@context": "https://schema.org",
      "@type": "FAQPage",
      "mainEntity": dynamicFaqs.map(faq => ({
        "@type": "Question",
        "name": faq.question,
        "acceptedAnswer": {
          "@type": "Answer",
          "text": faq.answer
        }
      }))
    });
  }

  // Inject into HTML
  let finalHtml = baseHtml;
  
  // Replace language
  finalHtml = finalHtml.replace(/<html lang="[^"]*">/, `<html lang="${lang}">`);
  
  // Replace Title
  finalHtml = finalHtml.replace(/<title>.*?<\/title>/, `<title>${title}</title>`);
  
  // Replace Meta Description - Fixing regex to allow space and self closing slash
  finalHtml = finalHtml.replace(/<meta name="description" content="[^"]*"\s*\/?>/i, `<meta name="description" content="${desc}" />`);
  
  // Inject JSON-LD right before </head>
  const scriptTag = `<script type="application/ld+json">\n${JSON.stringify(schemas, null, 2)}\n</script>`;
  finalHtml = finalHtml.replace('</head>', `  ${scriptTag}\n  </head>`);
  
  // Inject Hreflang
  const alternateUrl = lang === 'en' ? `https://www.theylovepdf.com/es${routePath}` : `https://www.theylovepdf.com${routePath.replace('/es/', '/')}`;
  const alternateLang = lang === 'en' ? 'es' : 'en';
  const hreflangTag = `<link rel="alternate" hreflang="${alternateLang}" href="${alternateUrl}" />\n    <link rel="alternate" hreflang="x-default" href="https://www.theylovepdf.com${routePath.replace('/es', '')}" />`;
  finalHtml = finalHtml.replace('</head>', `  ${hreflangTag}\n  </head>`);

  // Write file
  const outDir = path.join(DIST_DIR, routePath);
  fs.mkdirSync(outDir, { recursive: true });
  fs.writeFileSync(path.join(outDir, 'index.html'), finalHtml);
});

// Also create HTML for static pages
const staticRoutes = [
  '/pricing', '/compare', '/about', '/contact', '/privacy', '/terms', '/pdf-trends-2026'
];

staticRoutes.forEach(route => {
  const outDir = path.join(DIST_DIR, route);
  fs.mkdirSync(outDir, { recursive: true });
  fs.writeFileSync(path.join(outDir, 'index.html'), baseHtml); // simple fallback
});

console.log('✅ Static SEO HTML generation complete! 0 crashes guaranteed.');
